+/**
+ * Notification log model — tracks the history of all sent notifications.
+ *
+ * Every notification dispatched through the NotificationService is recorded
+ * as a NotificationLog entry, capturing recipient, channel, type, timestamp,
+ * and delivery status for auditing and querying.
+ */
+
+import type { NotificationChannel, NotificationType } from './notification.js';
+
+/**
+ * Delivery status of a notification.
+ */
+export type DeliveryStatus = 'sent' | 'delivered' | 'failed';
+
+/**
+ * A single notification log entry.
+ */
+export interface NotificationLog {
+  id: string;
+  notificationId: string;
+  recipient: string;
+  channel: NotificationChannel;
+  type: NotificationType;
+  subject: string;
+  body: string;
+  metadata?: Record<string, unknown>;
+  status: DeliveryStatus;
+  error?: string;
+  sentAt: Date;
+  createdAt: Date;
+}
+
+/**
+ * Query filters for retrieving notification history.
+ */
+export interface NotificationLogQuery {
+  userId?: string;
+  recipient?: string;
+  type?: NotificationType;
+  channel?: NotificationChannel;
+  status?: DeliveryStatus;
+  startDate?: Date;
+  endDate?: Date;
+}

