/**
 * Notification log model — tracks the history of all sent notifications.
 *
 * Every notification dispatched through the NotificationService is recorded
 * as a NotificationLog entry, capturing recipient, channel, type, timestamp,
 * and delivery status for auditing and querying.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

/**
 * Delivery status of a notification.
 */
export type DeliveryStatus = 'sent' | 'delivered' | 'failed';

/**
 * A single notification log entry.
 */
export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
  status: DeliveryStatus;
  error?: string;
  sentAt: Date;
  createdAt: Date;
}

/**
 * Query filters for retrieving notification history.
 */
export interface NotificationLogQuery {
  userId?: string;
  recipient?: string;
  type?: NotificationType;
  channel?: NotificationChannel;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods
 * for filtering by recipient, type, channel, status, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      metadata: record['metadata'] as Record<string, unknown> | undefined,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      sentAt: new Date(record['sentAt'] as string),
      createdAt: new Date(record['createdAt'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      body: entity.body,
      metadata: entity.metadata,
      status: entity.status,
      error: entity.error,
      sentAt: entity.sentAt.toISOString(),
      createdAt: entity.createdAt.toISOString(),
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll(
      (log) => log.sentAt >= startDate && log.sentAt <= endDate,
    );
  }

  findByNotificationId(notificationId: string): NotificationLog | undefined {
    const results = this.findAll((log) => log.notificationId === notificationId);
    return results[0];
  }
}

/**
 * Notification history service — records and queries notification delivery history.
 *
 * Receives notification results from the NotificationService and persists them
 * as NotificationLog entries via the NotificationLogRepository.
 * Provides query methods to retrieve history by user, type, channel, date range, etc.
 */

import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationLog, NotificationLogQuery, DeliveryStatus } from '../models/notification-log.js';
import type { Notification } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Record a sent notification in the history log.
   * Called by NotificationService after each send attempt.
   */
  record(notification: Notification): NotificationLog {
    const status: DeliveryStatus = notification.error
      ? 'failed'
      : notification.delivered
        ? 'delivered'
        : 'sent';

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: notification.id,
      recipient: notification.recipient,
      channel: notification.channel,
      type: notification.type,
      subject: notification.subject,
      body: notification.body,
      metadata: notification.metadata,
      status,
      error: notification.error,
      sentAt: notification.sentAt,
      createdAt: new Date(),
    };

    this.repository.save(log);
    this.logger.info(`Recorded notification ${notification.id} with status ${status}`);
    return log;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationLogQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.type && log.type !== filters.type) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.startDate && log.sentAt < filters.startDate) return false;
      if (filters.endDate && log.sentAt > filters.endDate) return false;
      if (filters.userId) {
        const logUserId = log.metadata?.['userId'] as string | undefined;
        if (logUserId !== filters.userId) return false;
      }
      return true;
    });
  }

  /**
   * Get all log entries for a specific user (by userId in metadata).
   */
  getByUser(userId: string): NotificationLog[] {
    return this.query({ userId });
  }

  /**
   * Get all log entries for a specific notification type.
   */
  getByType(type: NotificationLog['type']): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all log entries within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get all log entries for a specific channel.
   */
  getByChannel(channel: NotificationLog['channel']): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries with a specific delivery status.
   */
  getByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.repository.findByStatus(status);
  }

  /**
   * Get a log entry by the original notification ID.
   */
  getByNotificationId(notificationId: string): NotificationLog | undefined {
    return this.repository.findByNotificationId(notificationId);
  }

  /**
   * Get all notification log entries.
   */
  getAll(): NotificationLog[] {
    return this.repository.findAll();
  }

  /**
   * Get the total count of log entries.
   */
  count(): number {
    return this.repository.count();
  }
}

