import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import type { Notification } from '../../src/models/notification.js';
import type { UserCreatedEvent, OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    channel: 'email',
    metadata: { userId: 'user-1', orderId: 'order-1' },
    sentAt: new Date('2026-03-15T10:00:00Z'),
    delivered: true,
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repo: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repo);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a delivered notification', () => {
      const notification = makeNotification();
      const log = historyService.record(notification);

      expect(log.id).toBe('nlog-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order_confirmation');
      expect(log.status).toBe('delivered');
      expect(log.error).toBeUndefined();
    });

    it('should record a failed notification', () => {
      const notification = makeNotification({
        delivered: false,
        error: 'Connection refused',
      });
      const log = historyService.record(notification);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('Connection refused');
    });

    it('should record a sent-but-not-confirmed notification', () => {
      const notification = makeNotification({ delivered: false });
      const log = historyService.record(notification);

      expect(log.status).toBe('sent');
      expect(log.error).toBeUndefined();
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.record(makeNotification({ id: 'notif-0001' }));
      const log2 = historyService.record(makeNotification({ id: 'notif-0002' }));

      expect(log1.id).toBe('nlog-0001');
      expect(log2.id).toBe('nlog-0002');
    });

    it('should persist the log in the repository', () => {
      historyService.record(makeNotification());

      expect(repo.count()).toBe(1);
    });

    it('should capture subject and body', () => {
      const notification = makeNotification({
        subject: 'Important Update',
        body: 'Your order has shipped.',
      });
      const log = historyService.record(notification);

      expect(log.subject).toBe('Important Update');
      expect(log.body).toBe('Your order has shipped.');
    });

    it('should capture metadata', () => {
      const notification = makeNotification({
        metadata: { userId: 'user-42', orderId: 'order-99' },
      });
      const log = historyService.record(notification);

      expect(log.metadata).toEqual({ userId: 'user-42', orderId: 'order-99' });
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          channel: 'email',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-03-10T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'user_welcome',
          channel: 'email',
          metadata: { userId: 'user-2' },
          sentAt: new Date('2026-03-15T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0003',
          recipient: 'https://hook.example.com',
          type: 'order_status_update',
          channel: 'webhook',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-03-20T10:00:00Z'),
        }),
      );
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0001');
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'user_welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0003');
    });

    it('should query by userId', () => {
      const results = historyService.query({ userId: 'user-1' });
      expect(results).toHaveLength(2);
    });

    it('should query by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-03-12T00:00:00Z'),
        endDate: new Date('2026-03-18T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        userId: 'user-1',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0001');
    });

    it('should return empty array when no match', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('convenience query methods', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          channel: 'email',
          metadata: { userId: 'user-1' },
          sentAt: new Date('2026-03-10T10:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'user_welcome',
          channel: 'email',
          delivered: false,
          error: 'Mailbox full',
          metadata: { userId: 'user-2' },
          sentAt: new Date('2026-03-15T10:00:00Z'),
        }),
      );
    });

    it('getByUser should filter by userId in metadata', () => {
      const results = historyService.getByUser('user-1');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('alice@example.com');
    });

    it('getByType should filter by notification type', () => {
      const results = historyService.getByType('user_welcome');
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('getByDateRange should filter by date', () => {
      const results = historyService.getByDateRange(
        new Date('2026-03-12T00:00:00Z'),
        new Date('2026-03-18T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('getByChannel should filter by channel', () => {
      const results = historyService.getByChannel('email');
      expect(results).toHaveLength(2);
    });

    it('getByRecipient should filter by recipient', () => {
      const results = historyService.getByRecipient('bob@example.com');
      expect(results).toHaveLength(1);
    });

    it('getByStatus should filter by delivery status', () => {
      const failed = historyService.getByStatus('failed');
      expect(failed).toHaveLength(1);
      expect(failed[0]?.error).toBe('Mailbox full');

      const delivered = historyService.getByStatus('delivered');
      expect(delivered).toHaveLength(1);
    });

    it('getByNotificationId should find by original notification ID', () => {
      const log = historyService.getByNotificationId('notif-0001');
      expect(log).toBeDefined();
      expect(log?.recipient).toBe('alice@example.com');
    });

    it('getByNotificationId should return undefined for unknown ID', () => {
      expect(historyService.getByNotificationId('notif-9999')).toBeUndefined();
    });

    it('getAll should return all logs', () => {
      expect(historyService.getAll()).toHaveLength(2);
    });

    it('count should return total log entries', () => {
      expect(historyService.count()).toBe(2);
    });
  });

  describe('NotificationService integration', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      notificationService.registerAdapter(new EmailNotificationAdapter());
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should automatically log notifications sent via NotificationService', async () => {
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(1);
      const logs = historyService.getAll();
      expect(logs[0]?.type).toBe('user_welcome');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.status).toBe('delivered');
      expect(logs[0]?.channel).toBe('email');
    });

    it('should log multiple notifications from different events', async () => {
      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(2);
      const byUser = historyService.getByUser('user-1');
      expect(byUser).toHaveLength(2);
    });

    it('should log order status change notifications', async () => {
      await eventBus.emit<OrderStatusChangedEvent>({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      const logs = historyService.getByType('order_status_update');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.metadata).toEqual(
        expect.objectContaining({
          orderId: 'order-1',
          previousStatus: 'pending',
          newStatus: 'confirmed',
        }),
      );
    });

    it('should not log when notification is suppressed by preferences', async () => {
      // Create a mock preferences service that suppresses all notifications
      const mockPreferencesService = {
        shouldSendNotification: () => false,
        getPreferences: () => undefined,
        getOrCreatePreferences: () => ({}),
        createPreferences: () => ({}),
        updatePreferences: () => ({}),
        deletePreferences: () => true,
      } as any;
      notificationService.setPreferencesService(mockPreferencesService);

      await eventBus.emit<UserCreatedEvent>({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(0);
    });

    it('should work without history service (backward compatible)', async () => {
      const bus2 = new EventBus();
      const svc2 = new NotificationService(bus2);
      svc2.registerAdapter(new EmailNotificationAdapter());
      // No history service set

      await bus2.emit<UserCreatedEvent>({
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      });

      expect(svc2.getNotificationCount()).toBe(1);
      // historyService should still be empty since it's not connected to svc2
      expect(historyService.count()).toBe(0);
    });
  });
});
